query:
SELECT id, userId, businessDate, totalPoints, rawAchievementRate, kpiAchievementRate, overAchievementRate, finalKpiScore, createdAt, updatedAt FROM engineer_daily_productivity WHERE userId = 750192 ORDER BY businessDate DESC, updatedAt DESC;

SELECT businessDate, stationCode, COUNT(*) AS detailCount, ROUND(SUM(pointsAwarded), 6) AS detailPoints, SUM(CASE WHEN countForProductivity = 1 THEN 1 ELSE 0 END) AS countedRows FROM productivity_score_details WHERE userId = 750192 GROUP BY businessDate, stationCode ORDER BY businessDate DESC, stationCode;

SELECT COUNT(*) AS totalDetailRows, ROUND(SUM(pointsAwarded), 6) AS totalDetailPoints, SUM(CASE WHEN countForProductivity = 1 THEN 1 ELSE 0 END) AS countedRows FROM productivity_score_details WHERE userId = 750192;

